const salesData = items[0].json;
const supportData = items[1].json;

const totalRevenue = salesData.totalRevenue || salesData.total_revenue || 0;
const ticketsOpen  = supportData.open_tickets || supportData.ticketsOpen || 0;

return [
  {
    json: {
      reportDate: new Date().toISOString().slice(0,10),
      totalRevenue,
      ticketsOpen,
      salesData,
      supportData
    }
  }
];

const metrics = items[0].json;
const reportDate = metrics.reportDate;

const pdfContent = `Daily Report - ${reportDate}\n\nTotal Revenue: $${metrics.totalRevenue}\nOpen Support Tickets: ${metrics.ticketsOpen}\n`;
const buffer = Buffer.from(pdfContent, 'utf8');

return [
  {
    json: {
      ...metrics
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'application/pdf',
        fileName: `daily_report_${reportDate}.pdf`
      }
    }
  }
];

const metrics = $json;
const fileId  = $json.id || 'unknown';

return [
  {
    json: {
      mattermostText: `#### Daily Report (${metrics.reportDate})  \n• Total Revenue: $${metrics.totalRevenue}  \n• Open Tickets: ${metrics.ticketsOpen}  \n• HubSpot File ID: ${fileId}`,
      channel: $json.mattermostChannel || 'DAILY_REPORTS'
    }
  }
];

return [
  {
    json: {
      mattermostText: `❌ Daily Report workflow failed in one of the data or storage steps. Please review the execution logs.`,
      channel: 'DAILY_REPORTS'
    }
  }
];
